import { useState, useRef, useEffect } from 'react'
import { createPortal } from 'react-dom'
import { autoUpdate, computePosition, flip, offset, shift, size } from '@floating-ui/dom'
import * as LucideIcons from 'lucide-react'
import { FaSearch, FaTimes, FaChevronDown } from 'react-icons/fa'

export default function SearchableSelect({ options, value, onChange, placeholder, label: _label, isRTL, icon: _Icon, multiple = false, className = '', showAllOption = true, isClearable = true, dropdownZIndex = 10001, menuMode = 'portal' }) {
  const [isOpen, setIsOpen] = useState(false)
  const [search, setSearch] = useState('')
  const [coords, setCoords] = useState({ top: 0, left: 0, width: 0 })
  const wrapperRef = useRef(null)
  const dropdownRef = useRef(null)
  const rafRef = useRef(null)
  const cleanupAutoUpdateRef = useRef(null)
  const ignoreOutsideClass = 'react-datepicker-ignore-onclickoutside'
  const _lintKeep = { createPortal, FaSearch, FaTimes, FaChevronDown }

  const toText = (v) => (v === null || v === undefined ? '' : String(v))

  const updateCoords = async () => {
    if (!wrapperRef.current) return
    const rect = wrapperRef.current.getBoundingClientRect()

    if (menuMode !== 'portal' || !dropdownRef.current) {
      setCoords({ top: rect.bottom + window.scrollY + 4, left: rect.left + window.scrollX, width: rect.width })
      return
    }

    const bottomPlacement = isRTL ? 'bottom-end' : 'bottom-start'
    const topPlacement = isRTL ? 'top-end' : 'top-start'
    const { x, y } = await computePosition(wrapperRef.current, dropdownRef.current, {
      strategy: 'fixed',
      placement: bottomPlacement,
      middleware: [
        offset(4),
        // Only flip vertically (bottom <-> top). Avoid left/right fallback placements.
        flip({ padding: 8, fallbackPlacements: [topPlacement] }),
        // Keep the menu aligned horizontally with the trigger (no cross-axis shifting).
        shift({ padding: 8, mainAxis: true, crossAxis: false }),
        // Ensure the menu never exceeds viewport height (especially when flipped).
        size({
          padding: 8,
          apply({ availableHeight, elements }) {
            Object.assign(elements.floating.style, {
              maxHeight: `${Math.max(120, availableHeight)}px`,
            })
          },
        }),
      ],
    })

    setCoords({ top: y, left: x, width: rect.width })
  }

  const getOptionLabel = (opt) => {
    if (opt === null || opt === undefined) return ''
    if (typeof opt !== 'object') return opt
    if ('label' in opt) return opt.label
    if ('name' in opt) return opt.name
    if ('title' in opt) return opt.title
    if ('code' in opt) return opt.code
    if ('value' in opt) return opt.value
    if ('id' in opt) return opt.id
    return ''
  }

  const getOptionValue = (opt) => {
    if (opt === null || opt === undefined) return ''
    if (typeof opt !== 'object') return opt
    if ('value' in opt) return opt.value
    if ('id' in opt) return opt.id
    if ('name' in opt) return opt.name
    if ('label' in opt) return opt.label
    return ''
  }

  const renderIcon = (icon) => {
    if (!icon) return null;
    if (typeof icon !== 'string') return icon;
    const LucideIcon = LucideIcons[icon];
    if (LucideIcon) return <LucideIcon size={14} />;
    return icon;
  };

  useEffect(() => {
    function handleClickOutside(event) {
      const clickedWrapper = wrapperRef.current && wrapperRef.current.contains(event.target)
      const clickedDropdown = dropdownRef.current && dropdownRef.current.contains(event.target)
      if (!clickedWrapper && !clickedDropdown) {
        setIsOpen(false)
      }
    }

    function handleScroll(event) {
      if (!isOpen) return
      if (menuMode !== 'portal') return
      const target = event?.target
      const insideDropdown = target && dropdownRef.current && (dropdownRef.current === target || dropdownRef.current.contains(target))
      if (insideDropdown) return
      if (rafRef.current) cancelAnimationFrame(rafRef.current)
      rafRef.current = requestAnimationFrame(() => {
        updateCoords()
        rafRef.current = null
      })
    }

    document.addEventListener("mousedown", handleClickOutside)
    window.addEventListener("scroll", handleScroll, true)
    window.addEventListener("resize", handleScroll)

    return () => {
      document.removeEventListener("mousedown", handleClickOutside)
      window.removeEventListener("scroll", handleScroll, true)
      window.removeEventListener("resize", handleScroll)
      if (rafRef.current) cancelAnimationFrame(rafRef.current)
    }
  }, [isOpen, menuMode])

  useEffect(() => {
    if (!isOpen) return
    if (menuMode !== 'portal') return
    if (!wrapperRef.current || !dropdownRef.current) return

    if (cleanupAutoUpdateRef.current) cleanupAutoUpdateRef.current()
    cleanupAutoUpdateRef.current = autoUpdate(wrapperRef.current, dropdownRef.current, () => {
      updateCoords()
    }, { ancestorScroll: true, ancestorResize: true, elementResize: true })

    // first paint position
    updateCoords()

    return () => {
      if (cleanupAutoUpdateRef.current) cleanupAutoUpdateRef.current()
      cleanupAutoUpdateRef.current = null
    }
  }, [isOpen, menuMode, isRTL])

  const toggleOpen = () => {
    if (!isOpen && wrapperRef.current) {
      // position will be re-calculated after dropdown mounts too
      updateCoords()
    }
    setIsOpen(!isOpen)
  }

  const filteredOptions = (options || []).filter(opt => {
    if (!opt) return false;
    const labelText = toText(getOptionLabel(opt))
    return labelText.toLowerCase().includes(search.toLowerCase())
  })

  const isSelected = (opt) => {
    const val = getOptionValue(opt)
    return multiple ? Array.isArray(value) && value.includes(val) : value === val
  }
  
  const clearValue = () => multiple ? onChange([]) : onChange('')

  const getDisplayValue = () => {
    if (multiple) {
      if (Array.isArray(value) && value.length > 0) {
        return value.map(v => {
          const opt = (options || []).find(o => getOptionValue(o) === v)
          return opt ? toText(getOptionLabel(opt)) : toText(v)
        }).join(', ')
      }
      return placeholder || (showAllOption ? (isRTL ? 'الكل' : 'All') : '')
    }
    if (!value) return placeholder || (showAllOption ? (isRTL ? 'الكل' : 'All') : '')
    const opt = (options || []).find(o => getOptionValue(o) === value)
    return opt ? toText(getOptionLabel(opt)) : toText(value)
  }

  const isShowingPlaceholder = multiple
    ? !(Array.isArray(value) && value.length > 0)
    : !value

  const dropdownContent = (
    <div 
      ref={dropdownRef}
      style={{
        position: menuMode === 'portal' ? 'fixed' : 'relative',
        top: menuMode === 'portal' ? coords.top : 0,
        left: menuMode === 'portal' ? coords.left : 0,
        width: menuMode === 'portal' ? coords.width : '100%',
        marginTop: menuMode === 'portal' ? 0 : 6,
        zIndex: dropdownZIndex
      }}
      className={`${ignoreOutsideClass} rounded-xl shadow-xl bg-[var(--card-bg)] border border-[var(--panel-border)] backdrop-blur-md max-h-60 overflow-hidden flex flex-col`}
      dir={isRTL ? 'rtl' : 'ltr'}
    >
      <div className="p-2 border-b border-[var(--panel-border)]/70">
        <div className="relative">
          <FaSearch className={`absolute top-1/2 -translate-y-1/2 text-theme-text ${isRTL ? 'right-3' : 'left-3'}`} size={12} />
          <input
            autoFocus
            type="text"
            className={`${ignoreOutsideClass} input input-sm w-full bg-[var(--app-bg)] border border-[var(--panel-border)]/80 text-sm ${isRTL ? 'pr-8 pl-2' : 'pl-8 pr-2'} text-theme-text  placeholder-gray-500 dark:placeholder-gray-400 focus:outline-none focus:ring-0 focus:border-[var(--nova-accent)]`}
            placeholder={isRTL ? 'بحث...' : 'Search...'}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            onClick={(e) => e.stopPropagation()}
          />
        </div>
      </div>
      <div className={`${ignoreOutsideClass} overflow-y-auto max-h-48 py-1 scrollbar-thin-blue`}>
          {showAllOption && (
            <div
              className={`${ignoreOutsideClass} mx-1 rounded-lg px-3 py-2 cursor-pointer text-sm transition-colors ${(!multiple && value === '') || (multiple && Array.isArray(value) && value.length === 0) ? 'bg-[rgba(37,99,235,0.28)] text-white' : 'hover:bg-[rgba(37,99,235,0.18)]'} text-theme-text `}
              onClick={() => {
                clearValue()
                if (!multiple) setIsOpen(false)
                setSearch('')
              }}
            >
              {isRTL ? 'الكل' : 'All'}
            </div>
          )}
        {filteredOptions.length > 0 ? (
          filteredOptions.map((opt, idx) => {
            const label = toText(getOptionLabel(opt))
            const val = getOptionValue(opt)
            const color = typeof opt === 'object' && opt !== null && 'color' in opt ? opt.color : null
            const icon = typeof opt === 'object' && opt !== null && 'icon' in opt ? opt.icon : null
            return (
              <div
                key={idx}
                className={`${ignoreOutsideClass} mx-1 rounded-lg px-3 py-2 cursor-pointer text-sm transition-colors ${isSelected(opt) ? 'bg-[rgba(37,99,235,0.28)] text-white' : 'hover:bg-[rgba(37,99,235,0.18)]'} text-theme-text `}
                onClick={() => {
                  if (multiple) {
                    const cur = Array.isArray(value) ? value : []
                    const exists = cur.includes(val)
                    const next = exists ? cur.filter(v => v !== val) : [...cur, val]
                    onChange(next)
                  } else {
                    onChange(val)
                    setIsOpen(false)
                  }
                  setSearch('')
                }}
              >
                <div className={`${ignoreOutsideClass} flex items-center gap-2`}>
                   {icon && <span className={`${ignoreOutsideClass} shrink-0`}>{renderIcon(icon)}</span>}
                   {color && <span className={`${ignoreOutsideClass} w-2 h-2 rounded-full shrink-0`} style={{ backgroundColor: color }}></span>}
                   {label}
                </div>
              </div>
            )
          })
        ) : (
          <div className={`${ignoreOutsideClass} px-3 py-4 text-center text-sm text-[var(--muted-text)]`}>
            {isRTL ? 'لا توجد نتائج' : 'No results found'}
          </div>
        )}
      </div>
    </div>
  )

  return (
    <div className={`relative ${isOpen ? 'z-50' : ''}`} ref={wrapperRef}>
      <div
        className={`input w-full flex items-center justify-between cursor-pointer ${className}`}
        onClick={toggleOpen}
      >
        <span className={`text-sm ${isShowingPlaceholder ? 'text-slate-500 dark:text-gray-300' : 'text-theme-text'}`}>
          {getDisplayValue()}
        </span>
        <div className="flex items-center gap-2">
           {isClearable && ((!multiple && value && value !== 'All' && value !== 'الكل') || (multiple && Array.isArray(value) && value.length > 0)) ? (
             <FaTimes 
               className="text-theme-text hover:text-red-500 z-10" 
               size={12}
               onClick={(e) => {
                 e.stopPropagation()
                 clearValue()
               }}
             />
           ) : null}
           <FaChevronDown className={`text-theme-text transition-transform ${isOpen ? 'rotate-180' : ''}`} size={10} />
        </div>
      </div>

      {isOpen && (menuMode === 'portal' ? createPortal(dropdownContent, document.body) : dropdownContent)}
    </div>
  )
}
